Create a new component that shows glanceable Pulse/Relay/Mesh status chips in the sidebar footer.

## File
Create `apps/client/src/layers/features/session-list/ui/AgentContextChips.tsx`

## Implementation

```tsx
import { usePulseEnabled, useActiveRunCount } from '@/layers/entities/pulse';
import { useRelayEnabled } from '@/layers/entities/relay';
import { useRegisteredAgents } from '@/layers/entities/mesh';
import { useAppStore } from '@/layers/shared/model';
import { Tooltip, TooltipContent, TooltipTrigger } from '@/layers/shared/ui';
import { cn } from '@/layers/shared/lib';
// Import icons for Pulse, Relay, Mesh (use existing icon pattern from the codebase)

/**
 * Compact row of status chips showing Pulse/Relay/Mesh status at a glance.
 * Each chip opens its respective panel dialog on click.
 */
export function AgentContextChips() {
  const pulseEnabled = usePulseEnabled();
  const { data: activeRunCount = 0 } = useActiveRunCount(pulseEnabled);
  const relayEnabled = useRelayEnabled();
  const { data: agents = [] } = useRegisteredAgents();
  const { setPulseOpen, setRelayOpen, setMeshOpen } = useAppStore();

  return (
    <div className="flex items-center gap-1 px-2 py-1">
      {/* Pulse chip */}
      <Tooltip>
        <TooltipTrigger asChild>
          <button
            onClick={() => setPulseOpen(true)}
            className={cn(
              "relative rounded-md p-1.5 transition-colors",
              pulseEnabled
                ? "text-muted-foreground hover:text-foreground"
                : "text-muted-foreground/25 hover:text-muted-foreground/40"
            )}
            aria-label="Pulse scheduler"
          >
            {/* Use the Pulse icon from the existing icon set */}
            {/* icons.pulse or Timer or Clock icon */}
            {activeRunCount > 0 && (
              <span className="absolute -right-0.5 -top-0.5 size-2 rounded-full bg-green-500 animate-pulse" />
            )}
          </button>
        </TooltipTrigger>
        <TooltipContent side="top">
          {pulseEnabled
            ? activeRunCount > 0
              ? `${activeRunCount} run${activeRunCount > 1 ? 's' : ''} active`
              : 'Pulse — no active runs'
            : 'Pulse is disabled'}
        </TooltipContent>
      </Tooltip>

      {/* Relay chip — same pattern */}
      <Tooltip>
        <TooltipTrigger asChild>
          <button
            onClick={() => setRelayOpen(true)}
            className={cn(
              "relative rounded-md p-1.5 transition-colors",
              relayEnabled
                ? "text-muted-foreground hover:text-foreground"
                : "text-muted-foreground/25 hover:text-muted-foreground/40"
            )}
            aria-label="Relay messaging"
          >
            {/* Relay icon */}
          </button>
        </TooltipTrigger>
        <TooltipContent side="top">
          {relayEnabled ? 'Relay messaging' : 'Relay is disabled'}
        </TooltipContent>
      </Tooltip>

      {/* Mesh chip — same pattern */}
      <Tooltip>
        <TooltipTrigger asChild>
          <button
            onClick={() => setMeshOpen(true)}
            className={cn(
              "relative rounded-md p-1.5 transition-colors",
              "text-muted-foreground hover:text-foreground"
            )}
            aria-label="Mesh discovery"
          >
            {/* Mesh icon */}
            {agents.length > 0 && (
              <span className="absolute -right-0.5 -top-0.5 size-2 rounded-full bg-blue-500" />
            )}
          </button>
        </TooltipTrigger>
        <TooltipContent side="top">
          {agents.length > 0
            ? `${agents.length} agent${agents.length > 1 ? 's' : ''} registered`
            : 'No agents registered'}
        </TooltipContent>
      </Tooltip>
    </div>
  );
}
```

## Design Principles
- **Tooltip-first**: Status details shown in tooltips, not inline text. The footer is too narrow for labels.
- **Muted disabled states**: `text-muted-foreground/25` for disabled features — visually de-emphasizes without hiding.
- **Status dots**: Green animated dot for active Pulse runs; blue dot for registered Mesh agents.
- **Tappable**: Each chip opens its respective panel dialog via Zustand actions.
- **No new network requests**: Reuses existing entity hooks that are already fetching data.

## Acceptance Criteria
- Component renders 3 status chips (Pulse, Relay, Mesh)
- Each chip has a tooltip with contextual status text
- Disabled features show muted styling (`text-muted-foreground/25`)
- Active Pulse runs show an animated green dot
- Registered Mesh agents show a blue dot
- Clicking each chip opens the corresponding panel dialog
- All icons use the existing icon system/size conventions (`size-(--size-icon-sm)`)
- `pnpm typecheck` passes

Create the bottom footer bar with branding, settings button, and theme toggle.

## File
Create `apps/client/src/layers/features/session-list/ui/SidebarFooterBar.tsx`

## Implementation

```tsx
import { useCallback } from 'react';
import { Sun, Moon, Monitor, Settings } from 'lucide-react';
import { useAppStore, useTheme, type Theme } from '@/layers/shared/model';

/**
 * Bottom bar of the sidebar footer with branding link, settings button,
 * and theme cycle toggle.
 */
export function SidebarFooterBar() {
  const { setSettingsOpen } = useAppStore();
  const { theme, setTheme } = useTheme();
  const ThemeIcon = { light: Sun, dark: Moon, system: Monitor }[theme];

  const cycleTheme = useCallback(() => {
    const themeOrder: Theme[] = ['light', 'dark', 'system'];
    const idx = themeOrder.indexOf(theme);
    setTheme(themeOrder[(idx + 1) % themeOrder.length]);
  }, [theme, setTheme]);

  return (
    <div className="border-border flex items-center border-t px-2 py-1.5">
      <a
        href="https://dorkian.com"
        target="_blank"
        rel="noopener noreferrer"
        className="text-2xs text-muted-foreground/50 hover:text-muted-foreground transition-colors"
      >
        DorkOS by Dorkian
      </a>
      <div className="ml-auto flex items-center gap-0.5">
        <button
          onClick={() => setSettingsOpen(true)}
          className="text-muted-foreground/50 hover:text-muted-foreground rounded-md p-1 transition-colors"
          aria-label="Settings"
        >
          <Settings className="size-(--size-icon-sm)" />
        </button>
        <button
          onClick={cycleTheme}
          className="text-muted-foreground/50 hover:text-muted-foreground rounded-md p-1 transition-colors"
          aria-label={`Theme: ${theme}. Click to cycle.`}
        >
          <ThemeIcon className="size-(--size-icon-sm)" />
        </button>
        {import.meta.env.DEV && (
          /* DevtoolsToggle — import from wherever it currently lives */
          null
        )}
      </div>
    </div>
  );
}
```

## Details
- The `text-2xs` class should match the existing tiny text utility. If it doesn't exist, use `text-[10px]` or the smallest available text size.
- `size-(--size-icon-sm)` uses the existing icon size CSS variable. Check the codebase for the exact icon sizing pattern.
- The DevtoolsToggle conditional render (`import.meta.env.DEV`) should import the actual DevtoolsToggle component if one exists in the codebase. If not, skip it.
- Theme cycling order: light -> dark -> system -> light
- The branding link opens in a new tab

## Acceptance Criteria
- "DorkOS by Dorkian" branding link renders and opens https://dorkian.com in new tab
- Settings gear button calls `setSettingsOpen(true)` on click
- Theme toggle cycles through light -> dark -> system
- Theme icon changes based on current theme (Sun/Moon/Monitor)
- All buttons have aria-labels for accessibility
- Border-top separates this bar from the chips above
- `pnpm typecheck` passes

