    vi.clearAllMocks();
    mockTheme = 'light';
  });

  it('renders branding link', () => {
    render(<SidebarFooterBar />);
    const link = screen.getByText('DorkOS by Dorkian');
    expect(link).toBeInTheDocument();
    expect(link).toHaveAttribute('href', 'https://dorkian.com');
    expect(link).toHaveAttribute('target', '_blank');
    expect(link).toHaveAttribute('rel', 'noopener noreferrer');
  });

  it('opens settings on gear click', async () => {
    const user = userEvent.setup();
    render(<SidebarFooterBar />);
    await user.click(screen.getByLabelText('Settings'));
    expect(mockSetSettingsOpen).toHaveBeenCalledWith(true);
  });

  it('cycles theme light -> dark', async () => {
    mockTheme = 'light';
    const user = userEvent.setup();
    render(<SidebarFooterBar />);
    await user.click(screen.getByLabelText(/Theme: light/));
    expect(mockSetTheme).toHaveBeenCalledWith('dark');
  });

  it('cycles theme dark -> system', async () => {
    mockTheme = 'dark';
    const user = userEvent.setup();
    render(<SidebarFooterBar />);
    await user.click(screen.getByLabelText(/Theme: dark/));
    expect(mockSetTheme).toHaveBeenCalledWith('system');
  });

  it('cycles theme system -> light', async () => {
    mockTheme = 'system';
    const user = userEvent.setup();
    render(<SidebarFooterBar />);
    await user.click(screen.getByLabelText(/Theme: system/));
    expect(mockSetTheme).toHaveBeenCalledWith('light');
  });
});
